export interface InventoryItem {
  id: string;
  name: string;
  category: string;
  quantity: number;
  unit: string;
  qrCode: string;
}

export interface UsageLog {
  id: string;
  timestamp: string;
  itemId: string;
  itemName: string;
  user: string;
  amountChanged: number;
  action: 'USE' | 'RESTOCK';
}

export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  message?: string;
}

// Enum for App View State
export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SCANNER = 'SCANNER',
  ITEM_DETAILS = 'ITEM_DETAILS',
  LOGS = 'LOGS'
}

import { InventoryItem, UsageLog } from './types';

