import { InventoryItem, UsageLog, ApiResponse } from '../types';
import { INITIAL_ITEMS, INITIAL_LOGS, GOOGLE_SCRIPT_URL } from '../constants';

// Local storage keys for mock persistence
const STORAGE_ITEMS_KEY = 'rescue_inventory_items';
const STORAGE_LOGS_KEY = 'rescue_inventory_logs';

const isDemo = !GOOGLE_SCRIPT_URL;

// Helper to simulate delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const api = {
  /**
   * Fetch all inventory items
   */
  getInventory: async (): Promise<InventoryItem[]> => {
    if (isDemo) {
      await delay(600);
      const stored = localStorage.getItem(STORAGE_ITEMS_KEY);
      if (stored) return JSON.parse(stored);
      localStorage.setItem(STORAGE_ITEMS_KEY, JSON.stringify(INITIAL_ITEMS));
      return INITIAL_ITEMS;
    } else {
      try {
        const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getInventory`);
        const data: ApiResponse<InventoryItem[]> = await response.json();
        return data.data || [];
      } catch (error) {
        console.error("API Error", error);
        return [];
      }
    }
  },

  /**
   * Log usage and update stock
   */
  logUsage: async (itemId: string, quantity: number, user: string): Promise<boolean> => {
    const actionType = quantity < 0 ? 'USE' : 'RESTOCK';

    if (isDemo) {
      await delay(800);

      // Update Items
      const storedItemsStr = localStorage.getItem(STORAGE_ITEMS_KEY);
      const items: InventoryItem[] = storedItemsStr ? JSON.parse(storedItemsStr) : INITIAL_ITEMS;
      const updatedItems = items.map(item => {
        if (item.id === itemId) {
          return { ...item, quantity: item.quantity + quantity }; // Quantity is negative for usage
        }
        return item;
      });
      localStorage.setItem(STORAGE_ITEMS_KEY, JSON.stringify(updatedItems));

      // Add Log
      const storedLogsStr = localStorage.getItem(STORAGE_LOGS_KEY);
      const logs: UsageLog[] = storedLogsStr ? JSON.parse(storedLogsStr) : INITIAL_LOGS;

      const targetItem = items.find(i => i.id === itemId);

      const newLog: UsageLog = {
        id: Date.now().toString(),
        timestamp: new Date().toISOString(),
        itemId,
        itemName: targetItem?.name || 'Unknown',
        user,
        amountChanged: quantity,
        action: actionType
      };

      localStorage.setItem(STORAGE_LOGS_KEY, JSON.stringify([newLog, ...logs]));
      return true;
    } else {
      // Real API Call
      try {
        const payload = {
          action: 'logUsage',
          itemId,
          quantity, // Send negative number for usage
          user
        };

        // Google Apps Script usually requires no-cors for simple GET/POST from browser if not properly set up,
        // but text/plain POST is standard for GAS Web Apps to avoid preflight CORS issues.
        await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          body: JSON.stringify(payload)
        });
        return true;
      } catch (error) {
        console.error("API Error", error);
        return false;
      }
    }
  },

  /**
   * Get logs
   */
  getLogs: async (): Promise<UsageLog[]> => {
    if (isDemo) {
      await delay(500);
      const stored = localStorage.getItem(STORAGE_LOGS_KEY);
      if (stored) return JSON.parse(stored);
      return INITIAL_LOGS;
    } else {
       try {
        const response = await fetch(`${GOOGLE_SCRIPT_URL}?action=getLogs`);
        const data: ApiResponse<UsageLog[]> = await response.json();
        return data.data || [];
      } catch (error) {
        console.error("API Error", error);
        return [];
      }
    }
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { Html5QrcodeScanner } from 'html5-qrcode';
import { X } from 'lucide-react';

interface QRScannerProps {
  onScanSuccess: (decodedText: string) => void;
  onClose: () => void;
}

const QRScanner: React.FC<QRScannerProps> = ({ onScanSuccess, onClose }) => {
  const [scanError, setScanError] = useState<string | null>(null);
  const scannerRef = useRef<Html5QrcodeScanner | null>(null);

  useEffect(() => {
    // Initialize scanner
    // Note: In a real environment, ensure this is running on HTTPS
    const scanner = new Html5QrcodeScanner(
      "reader",
      { 
        fps: 10, 
        qrbox: { width: 250, height: 250 },
        aspectRatio: 1.0 
      },
      /* verbose= */ false
    );

    scanner.render(
      (decodedText) => {
        // Success callback
        scanner.clear().then(() => {
           onScanSuccess(decodedText);
        }).catch(err => {
            console.error("Failed to clear scanner", err);
            onScanSuccess(decodedText); // Still proceed
        });
      },
      (errorMessage) => {
        // Error callback (called frequently when no QR is found)
        // We generally ignore this unless it's a permission error
        // console.log(errorMessage); 
      }
    );

    scannerRef.current = scanner;

    return () => {
      if (scannerRef.current) {
        scannerRef.current.clear().catch(error => {
          console.error("Failed to clear html5-qrcode scanner during cleanup.", error);
        });
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="fixed inset-0 z-50 bg-black bg-opacity-90 flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-lg overflow-hidden relative">
        <div className="p-4 bg-gray-100 flex justify-between items-center border-b">
          <h2 className="text-lg font-bold text-gray-800">Skannaa QR-koodi</h2>
          <button onClick={onClose} className="p-2 text-gray-600 hover:text-red-600">
            <X size={24} />
          </button>
        </div>

        <div className="p-4">
          <div id="reader" className="w-full h-auto min-h-[300px] bg-black"></div>
          {scanError && <p className="text-red-500 text-sm mt-2 text-center">{scanError}</p>}
        </div>

        <div className="p-4 bg-gray-50 text-center text-sm text-gray-500">
           Osoita kamera tuotteen QR-koodiin.
        </div>
      </div>
    </div>
  );
};

export default QRScanner;

import React, { useState } from 'react';
import { InventoryItem } from '../types';
import { Check, X, AlertTriangle } from 'lucide-react';

interface UsageModalProps {
  item: InventoryItem;
  onConfirm: (quantity: number, user: string) => void;
  onCancel: () => void;
  isSubmitting: boolean;
}

const UsageModal: React.FC<UsageModalProps> = ({ item, onConfirm, onCancel, isSubmitting }) => {
  const [amount, setAmount] = useState<string>('1');
  const [user, setUser] = useState<string>('');
  const [mode, setMode] = useState<'USE' | 'ADD'>('USE');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const qty = parseInt(amount, 10);
    if (isNaN(qty) || qty <= 0) return;
    if (!user.trim()) return;

    // If using, amount is negative. If adding, positive.
    const finalAmount = mode === 'USE' ? -qty : qty;
    onConfirm(finalAmount, user);
  };

  const currentStock = item.quantity;
  const requested = parseInt(amount) || 0;
  const isStockLow = mode === 'USE' && (currentStock - requested < 0);

  return (
    <div className="fixed inset-0 z-40 bg-black bg-opacity-75 flex items-center justify-center p-4">
      <form onSubmit={handleSubmit} className="w-full max-w-sm bg-white rounded-xl shadow-2xl overflow-hidden">
        {/* Header */}
        <div className={`p-4 text-white flex justify-between items-center ${mode === 'USE' ? 'bg-red-600' : 'bg-green-600'}`}>
          <h3 className="text-lg font-bold">{mode === 'USE' ? 'Kirjaa Käyttö' : 'Kirjaa Lisäys'}</h3>
          <button type="button" onClick={onCancel} className="text-white hover:bg-white/20 rounded-full p-1">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 space-y-4">

          {/* Item Info */}
          <div className="mb-4">
            <h4 className="text-xl font-bold text-gray-800">{item.name}</h4>
            <p className="text-sm text-gray-500 uppercase tracking-wide">{item.category}</p>
            <div className="mt-2 flex items-center gap-2">
              <span className="text-sm font-semibold text-gray-600">Nykyinen varasto:</span>
              <span className={`text-lg font-mono font-bold ${item.quantity < 5 ? 'text-red-500' : 'text-gray-800'}`}>
                {item.quantity} {item.unit}
              </span>
            </div>
          </div>

          {/* Mode Toggle */}
          <div className="flex bg-gray-100 p-1 rounded-lg">
            <button
              type="button"
              onClick={() => setMode('USE')}
              className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors ${mode === 'USE' ? 'bg-white text-red-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              Käytä
            </button>
            <button
              type="button"
              onClick={() => setMode('ADD')}
              className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors ${mode === 'ADD' ? 'bg-white text-green-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
            >
              Lisää (Täydennys)
            </button>
          </div>

          {/* Inputs */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Määrä ({item.unit})</label>
            <input
              type="number"
              min="1"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="w-full text-center text-3xl font-bold p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none border-gray-300"
              required
            />
            {isStockLow && (
              <div className="mt-2 text-red-500 text-sm flex items-center gap-1">
                <AlertTriangle size={16} />
                <span>Varoitus: Varasto menee miinukselle!</span>
              </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Käyttäjän nimi</label>
            <input
              type="text"
              value={user}
              onChange={(e) => setUser(e.target.value)}
              placeholder="Esim. Matti M."
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              required
            />
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-gray-50 border-t flex gap-3">
          <button
            type="button"
            onClick={onCancel}
            className="flex-1 py-3 px-4 bg-white border border-gray-300 text-gray-700 font-medium rounded-lg hover:bg-gray-50 transition-colors"
          >
            Peruuta
          </button>
          <button
            type="submit"
            disabled={isSubmitting || !user.trim()}
            className={`flex-1 py-3 px-4 text-white font-medium rounded-lg flex justify-center items-center gap-2 transition-colors
              ${mode === 'USE' 
                ? 'bg-red-600 hover:bg-red-700 disabled:bg-red-300' 
                : 'bg-green-600 hover:bg-green-700 disabled:bg-green-300'
              }`}
          >
            {isSubmitting ? 'Tallennetaan...' : (
              <>
                <Check size={20} />
                {mode === 'USE' ? 'Kirjaa otto' : 'Kirjaa tulo'}
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

export default UsageModal;

import React, { useState, useEffect, useCallback } from 'react';
import { QrCode, ClipboardList, History, Search, RefreshCw, AlertCircle } from 'lucide-react';
import { InventoryItem, UsageLog, AppView } from './types';
import { api } from './services/api';
import QRScanner from './components/QRScanner';
import UsageModal from './components/UsageModal';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [logs, setLogs] = useState<UsageLog[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [statusMsg, setStatusMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [itemsData, logsData] = await Promise.all([
        api.getInventory(),
        api.getLogs()
      ]);
      setItems(itemsData);
      setLogs(logsData);
    } catch (e) {
      console.error(e);
      setStatusMsg({ type: 'error', text: 'Virhe ladattaessa tietoja.' });
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Handle QR Scan Result
  const handleScanSuccess = (decodedText: string) => {
    // Attempt to find item by QR code
    const found = items.find(i => i.qrCode === decodedText || i.id === decodedText);

    if (found) {
      setSelectedItem(found);
      setView(AppView.DASHBOARD); // Close scanner view, modal will open
    } else {
      alert(`Tuotetta koodilla "${decodedText}" ei löytynyt.`);
      setView(AppView.DASHBOARD);
    }
  };

  const handleTransaction = async (qty: number, user: string) => {
    if (!selectedItem) return;
    setIsSubmitting(true);

    const success = await api.logUsage(selectedItem.id, qty, user);

    if (success) {
      setStatusMsg({ type: 'success', text: 'Kirjaus tallennettu onnistuneesti!' });
      setSelectedItem(null);
      await loadData(); // Refresh data
    } else {
      setStatusMsg({ type: 'error', text: 'Tallennus epäonnistui. Tarkista yhteys.' });
    }

    setIsSubmitting(false);
    setTimeout(() => setStatusMsg(null), 3000);
  };

  const filteredItems = items.filter(i => 
    i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    i.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen pb-20 max-w-lg mx-auto bg-gray-50 shadow-2xl overflow-hidden relative border-x border-gray-200">
      {/* Header */}
      <header className="bg-gradient-to-r from-red-700 to-red-600 text-white p-6 shadow-md sticky top-0 z-10">
        <div className="flex justify-between items-center mb-4">
           <div>
             <h1 className="text-2xl font-bold">PelastusVarasto</h1>
             <p className="text-red-100 text-xs opacity-90">Harjoitusalueen hallinta</p>
           </div>
           <button onClick={loadData} className="p-2 hover:bg-white/10 rounded-full transition-colors">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>

        {/* Stats Summary */}
        <div className="flex gap-4">
          <div className="bg-white/10 rounded-lg p-3 flex-1 backdrop-blur-sm">
             <span className="block text-2xl font-bold">{items.length}</span>
             <span className="text-xs text-red-100">Nimikettä</span>
          </div>
           <div className="bg-white/10 rounded-lg p-3 flex-1 backdrop-blur-sm">
             <span className="block text-2xl font-bold">{logs.length}</span>
             <span className="text-xs text-red-100">Tapahtumaa</span>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="p-4">

        {/* Status Message Toast */}
        {statusMsg && (
          <div className={`mb-4 p-4 rounded-lg flex items-center gap-3 text-sm font-medium animate-bounce-in
            ${statusMsg.type === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
            <AlertCircle size={20} />
            {statusMsg.text}
          </div>
        )}

        {view === AppView.DASHBOARD && (
          <div className="space-y-4">

            {/* Quick Action: Scan */}
            <button
              onClick={() => setView(AppView.SCANNER)}
              className="w-full bg-gray-900 text-white p-6 rounded-xl shadow-lg flex items-center justify-center gap-4 hover:bg-gray-800 transition-transform active:scale-95"
            >
              <QrCode size={32} />
              <div className="text-left">
                <span className="block text-lg font-bold">Skannaa tuote</span>
                <span className="text-gray-400 text-sm">Käytä kameraa kirjaukseen</span>
              </div>
            </button>

            {/* Inventory List Header & Search */}
            <div className="mt-8">
              <div className="flex justify-between items-center mb-4">
                 <h2 className="text-lg font-bold text-gray-800">Varastotilanne</h2>
              </div>

              <div className="relative mb-4">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Etsi tuotetta..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 bg-white border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                />
              </div>

              {/* Items List */}
              <div className="space-y-3">
                {loading ? (
                  <div className="text-center py-10 text-gray-400">Ladataan...</div>
                ) : filteredItems.length === 0 ? (
                  <div className="text-center py-10 text-gray-400">Ei tuotteita.</div>
                ) : (
                  filteredItems.map(item => (
                    <div 
                      key={item.id} 
                      onClick={() => setSelectedItem(item)}
                      className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex justify-between items-center active:bg-gray-50 cursor-pointer"
                    >
                      <div>
                        <h3 className="font-semibold text-gray-800">{item.name}</h3>
                        <span className="inline-block px-2 py-0.5 bg-gray-100 text-gray-500 text-xs rounded-md mt-1">
                          {item.category}
                        </span>
                      </div>
                      <div className="text-right">
                        <div className={`text-xl font-mono font-bold ${item.quantity < 5 ? 'text-red-500' : 'text-gray-800'}`}>
                          {item.quantity}
                        </div>
                        <span className="text-xs text-gray-400">{item.unit}</span>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}

        {view === AppView.LOGS && (
          <div className="space-y-4">
            <h2 className="text-lg font-bold text-gray-800 mb-4">Käyttöhistoria</h2>
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 divide-y">
              {logs.map((log) => (
                <div key={log.id} className="p-4 flex justify-between items-start">
                  <div>
                    <div className="font-medium text-gray-800">{log.itemName}</div>
                    <div className="text-sm text-gray-500 flex flex-col sm:flex-row sm:gap-2">
                       <span>{log.user}</span>
                       <span className="hidden sm:inline">•</span>
                       <span>{new Date(log.timestamp).toLocaleString('fi-FI')}</span>
                    </div>
                  </div>
                  <div className={`font-mono font-bold ${log.amountChanged < 0 ? 'text-red-500' : 'text-green-600'}`}>
                    {log.amountChanged > 0 ? '+' : ''}{log.amountChanged}
                  </div>
                </div>
              ))}
              {logs.length === 0 && <div className="p-6 text-center text-gray-400">Ei historiaa.</div>}
            </div>
          </div>
        )}

      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 w-full max-w-lg bg-white border-t border-gray-200 flex justify-around p-2 pb-4 z-20">
        <button 
          onClick={() => setView(AppView.DASHBOARD)}
          className={`p-2 flex flex-col items-center gap-1 min-w-[64px] ${view === AppView.DASHBOARD ? 'text-red-600' : 'text-gray-400'}`}
        >
          <ClipboardList size={24} />
          <span className="text-[10px] font-medium">Varasto</span>
        </button>

        <div className="relative -top-6">
          <button 
            onClick={() => setView(AppView.SCANNER)}
            className="bg-red-600 text-white p-4 rounded-full shadow-lg hover:bg-red-700 hover:scale-105 transition-all"
          >
            <QrCode size={28} />
          </button>
        </div>

        <button 
          onClick={() => setView(AppView.LOGS)}
          className={`p-2 flex flex-col items-center gap-1 min-w-[64px] ${view === AppView.LOGS ? 'text-red-600' : 'text-gray-400'}`}
        >
          <History size={24} />
          <span className="text-[10px] font-medium">Logi</span>
        </button>
      </nav>

      {/* Overlays */}
      {view === AppView.SCANNER && (
        <QRScanner 
          onScanSuccess={handleScanSuccess} 
          onClose={() => setView(AppView.DASHBOARD)} 
        />
      )}

      {selectedItem && (
        <UsageModal 
          item={selectedItem}
          onConfirm={handleTransaction}
          onCancel={() => setSelectedItem(null)}
          isSubmitting={isSubmitting}
        />
      )}
    </div>
  );
};

export default App;

# PelastusVarasto Backend

Tämä sovellus vaatii toimiakseen Google Apps Script -taustajärjestelmän (backend), joka on yhdistetty Google Sheetiin.

## Asennusohjeet

1.  Luo uusi **Google Sheet**.
2.  Luo kaksi välilehteä: `Varasto` ja `Lokit`.
3.  Lisää otsikot **Varasto**-välilehden ensimmäiselle riville:
    *   A1: `Tunniste`
    *   B1: `Nimi`
    *   C1: `Kategoria`
    *   D1: `Määrä`
    *   E1: `Yksikkö`
    *   F1: `QR-koodi`
4.  Lisää otsikot **Lokit**-välilehden ensimmäiselle riville:
    *   A1: `Loki ID`
    *   B1: `Aikaleima`
    *   C1: `Tuote ID`
    *   D1: `Tuotteen Nimi`
    *   E1: `Käyttäjä`
    *   F1: `Muutos`
    *   G1: `Toiminto`
5.  Avaa Sheetissä valikko **Laajennukset** > **Apps Script**.
6.  Poista kaikki oletuskoodi ja kopioi alla oleva koodi tilalle.
7.  Tallenna projekti.
8.  Julkaise sovellus:
    *   Klikkaa **Ota käyttöön** (Deploy) > **Uusi käyttöönotto** (New deployment).
    *   Valitse tyypiksi **Verkkosovellus** (Web app).
    *   Kuvaus: "Versio 1".
    *   Suorita käyttäjänä: **Minä** (Me).
    *   Kuka voi käyttää: **Kuka tahansa** (Anyone). **TÄRKEÄÄ: Valitse "Kuka tahansa" (Anyone), jotta sovellus toimii ilman kirjautumista.**
    *   Klikkaa **Ota käyttöön**.
9.  Kopioi saamasi **Verkkosovelluksen URL-osoite**.
10. Liitä URL-osoite React-sovelluksen tiedostoon `constants.ts` kohtaan `GOOGLE_SCRIPT_URL`.

## Google Apps Script Koodi (`backend-script.gs`)

```javascript
const SHEET_INVENTORY = "Varasto";
const SHEET_LOGS = "Lokit";

// Sarakkeiden indeksit (0 = sarake A, 1 = sarake B, jne.)
// Varasto: Tunniste(0), Nimi(1), Kategoria(2), Määrä(3), Yksikkö(4), QR-koodi(5)
const COL_ID = 0;
const COL_NAME = 1;
const COL_CATEGORY = 2;
const COL_QUANTITY = 3;
const COL_UNIT = 4;
const COL_QR = 5;

// Lokit: Loki ID(0), Aikaleima(1), Tuote ID(2), Tuotteen Nimi(3), Käyttäjä(4), Muutos(5), Toiminto(6)
const LOG_COL_ID = 0;
const LOG_COL_TIMESTAMP = 1;
const LOG_COL_ITEM_ID = 2;
const LOG_COL_ITEM_NAME = 3;
const LOG_COL_USER = 4;
const LOG_COL_CHANGE = 5;
const LOG_COL_ACTION = 6;

function doGet(e) {
  const action = e.parameter.action;

  if (action === 'getInventory') {
    return getInventory();
  } else if (action === 'getLogs') {
    return getLogs();
  }

  return response({ success: false, message: "Tuntematon toiminto" });
}

function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);
    const action = data.action;

    if (action === 'logUsage') {
      return logUsage(data);
    }

    return response({ success: false, message: "Tuntematon toiminto" });
  } catch (err) {
    return response({ success: false, message: "Virhe pyynnön käsittelyssä: " + err.toString() });
  }
}

function getInventory() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_INVENTORY);

  // Jos välilehteä ei löydy, palautetaan tyhjä lista
  if (!sheet) return response({ success: true, data: [] });

  const lastRow = sheet.getLastRow();
  if (lastRow < 2) return response({ success: true, data: [] });

  const data = sheet.getRange(2, 1, lastRow - 1, 6).getValues();

  const inventory = data.map(row => ({
    id: row[COL_ID].toString(),
    name: row[COL_NAME],
    category: row[COL_CATEGORY],
    quantity: Number(row[COL_QUANTITY]),
    unit: row[COL_UNIT],
    qrCode: row[COL_QR]
  }));

  return response({ success: true, data: inventory });
}

function getLogs() {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName(SHEET_LOGS);

  if (!sheet) return response({ success: true, data: [] });

  const lastRow = sheet.getLastRow();
  if (lastRow <= 1) return response({ success: true, data: [] });

  // Haetaan viimeiset 50 lokimerkintää
  const startRow = Math.max(2, lastRow - 49);
  const numRows = lastRow - startRow + 1;

  const data = sheet.getRange(startRow, 1, numRows, 7).getValues();

  // Käännetään järjestys (uusin ensin)
  const logs = data.reverse().map(row => ({
    id: row[LOG_COL_ID].toString(),
    timestamp: row[LOG_COL_TIMESTAMP],
    itemId: row[LOG_COL_ITEM_ID].toString(),
    itemName: row[LOG_COL_ITEM_NAME],
    user: row[LOG_COL_USER],
    amountChanged: Number(row[LOG_COL_CHANGE]),
    action: row[LOG_COL_ACTION]
  }));

  return response({ success: true, data: logs });
}

function logUsage(data) {
  const itemId = data.itemId;
  const qtyChange = Number(data.quantity);
  const user = data.user;

  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const invSheet = ss.getSheetByName(SHEET_INVENTORY);
  const logSheet = ss.getSheetByName(SHEET_LOGS);

  if (!invSheet || !logSheet) {
     return response({ success: false, message: "Välilehtiä puuttuu Sheetistä." });
  }

  const invData = invSheet.getDataRange().getValues();
  let rowIndex = -1;
  let currentItem = null;

  // Etsitään tuote ID:n perusteella (skipataan otsikkorivi 0)
  for (let i = 1; i < invData.length; i++) {
    if (invData[i][COL_ID].toString() === itemId.toString()) {
      rowIndex = i + 1; // 1-based index
      currentItem = invData[i];
      break;
    }
  }

  if (rowIndex === -1) {
    return response({ success: false, message: "Tuotetta ei löytynyt" });
  }

  // Päivitetään varastosaldo
  const currentQty = Number(currentItem[COL_QUANTITY]);
  const newQty = currentQty + qtyChange;
  invSheet.getRange(rowIndex, COL_QUANTITY + 1).setValue(newQty);

  // Lisätään lokimerkintä
  const logId = new Date().getTime().toString();
  const timestamp = new Date().toISOString();
  const itemName = currentItem[COL_NAME];
  const actionType = qtyChange < 0 ? 'USE' : 'RESTOCK';

  logSheet.appendRow([
    logId, 
    timestamp, 
    itemId, 
    itemName, 
    user, 
    qtyChange, 
    actionType
  ]);

  return response({ success: true, message: "Päivitys onnistui" });
}

function response(obj) {
  return ContentService.createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}
