# PelastusVarasto Backend

Tämä sovellus vaatii toimiakseen Google Apps Script -taustajärjestelmän (backend), joka on yhdistetty Google Sheetiin.

## Asennusohjeet

1.  Luo uusi **Google Sheet**.
2.  Luo kaksi välilehteä: `Varasto` ja `Lokit`.
3.  Lisää otsikot **Varasto**-välilehden ensimmäiselle riville tässä järjestyksessä:
    *   A1: `Tunniste` (ID)
    *   B1: `Nimi`
    *   C1: `Kategoria`
    *   D1: `Yksikkö` (Huom: Ennen määrää)
    *   E1: `Määrä` (Numero)
    *   F1: `QR-koodi`
4.  Lisää otsikot **Lokit**-välilehden ensimmäiselle riville:
    *   A1: `Loki ID`
    *   B1: `Aikaleima`
    *   C1: `Tuote ID`
    *   D1: `Tuotteen Nimi`
    *   E1: `Käyttäjä`
    *   F1: `Muutos`
    *   G1: `Toiminto`
5.  Avaa Sheetissä valikko **Laajennukset** > **Apps Script**.
6.  Poista kaikki oletuskoodi ja kopioi alla oleva koodi (tai `backend-script.gs` tiedoston sisältö) tilalle.
7.  Tallenna projekti.
8.  Julkaise sovellus:
    *   Klikkaa **Ota käyttöön** (Deploy) > **Uusi käyttöönotto** (New deployment).
    *   Valitse tyypiksi **Verkkosovellus** (Web app).
    *   Kuvaus: "Versio 3".
    *   Suorita käyttäjänä: **Minä** (Me).
    *   Kuka voi käyttää: **Kuka tahansa** (Anyone). **TÄRKEÄÄ: Valitse "Kuka tahansa" (Anyone), jotta sovellus toimii ilman kirjautumista.**
    *   Klikkaa **Ota käyttöön**.
9.  Kopioi saamasi **Verkkosovelluksen URL-osoite**.
10. Liitä URL-osoite React-sovelluksen tiedostoon `constants.ts` kohtaan `GOOGLE_SCRIPT_URL`. 

---

## Google Apps Script Koodi

Kopioi tämä koodi Google Apps Script -editoriin:

```javascript
/**
 * PELASTUSVARASTO BACKEND SCRIPT
 * 
 * Column Mapping (0-based index for array, 1-based for Sheet ranges):
 * 0 (A): ID
 * 1 (B): Name
 * 2 (C): Category
 * 3 (D): Unit (Yksikkö)
 * 4 (E): Quantity (Määrä)
 * 5 (F): QR Code
 */

// Define column indices for easy adjustment
var COL_ID = 0;
var COL_NAME = 1;
var COL_CATEGORY = 2;
var COL_UNIT = 3;      // Column D
var COL_QUANTITY = 4;  // Column E
var COL_QR = 5;        // Column F

function doGet(e) {
  return handleRequest(e);
}

function doPost(e) {
  return handleRequest(e);
}

function handleRequest(e) {
  var lock = LockService.getScriptLock();
  lock.tryLock(10000);

  try {
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var params = e.parameter;

    if (e.postData && e.postData.contents) {
      try {
        var jsonBody = JSON.parse(e.postData.contents);
        for (var key in jsonBody) {
          params[key] = jsonBody[key];
        }
      } catch (err) {
        Logger.log("JSON Parse error: " + err);
      }
    }

    var action = params.action;
    var result = { success: false, message: "Invalid action" };

    if (action === "getInventory") {
      result = getInventory(ss);
    } else if (action === "logUsage") {
      result = logUsage(ss, params);
    } else if (action === "getLogs") {
      result = getLogs(ss);
    }

    return ContentService.createTextOutput(JSON.stringify(result))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({
      success: false, 
      message: error.toString()
    })).setMimeType(ContentService.MimeType.JSON);
  } finally {
    lock.releaseLock();
  }
}

function getInventory(ss) {
  var sheet = ss.getSheetByName("Varasto");
  if (!sheet) return { success: false, message: "Sheet 'Varasto' not found" };

  var data = sheet.getDataRange().getValues();
  var items = [];

  for (var i = 1; i < data.length; i++) {
    var row = data[i];
    if (row[COL_ID]) {
       items.push({
        id: String(row[COL_ID]),
        name: row[COL_NAME],
        category: row[COL_CATEGORY],
        quantity: Number(row[COL_QUANTITY]), // Read from Col E
        unit: row[COL_UNIT],                 // Read from Col D
        qrCode: String(row[COL_QR])
      });
    }
  }

  return { success: true, data: items };
}

function getLogs(ss) {
  var sheet = ss.getSheetByName("Lokit");
  if (!sheet) return { success: true, data: [] };

  var lastRow = sheet.getLastRow();
  if (lastRow <= 1) return { success: true, data: [] };

  var startRow = Math.max(2, lastRow - 49);
  var numRows = lastRow - startRow + 1;

  var data = sheet.getRange(startRow, 1, numRows, 7).getValues();
  var logs = [];

  for (var i = data.length - 1; i >= 0; i--) {
    var row = data[i];
    logs.push({
      id: String(row[0]),
      timestamp: row[1],
      itemId: String(row[2]),
      itemName: row[3],
      user: row[4],
      amountChanged: Number(row[5]),
      action: row[6]
    });
  }

  return { success: true, data: logs };
}

function logUsage(ss, params) {
  var itemId = params.itemId;
  var quantityChange = Number(params.quantity);
  var user = params.user;
  // Use explicit actionType if provided, otherwise fallback to inference
  var explicitActionType = params.actionType;

  if (!itemId || isNaN(quantityChange) || !user) {
    return { success: false, message: "Missing required parameters" };
  }

  var invSheet = ss.getSheetByName("Varasto");
  var logSheet = ss.getSheetByName("Lokit");

  var data = invSheet.getDataRange().getValues();
  var rowIndex = -1;
  var currentName = "Unknown";

  for (var i = 1; i < data.length; i++) {
    if (String(data[i][COL_ID]) === String(itemId)) {
      rowIndex = i + 1;
      currentName = data[i][COL_NAME];
      // Read current quantity from Correct Column
      var currentQty = Number(data[i][COL_QUANTITY]);

      // Calculate new quantity
      var newQty = currentQty + quantityChange;

      // Update quantity in Correct Column (1-based index)
      invSheet.getRange(rowIndex, COL_QUANTITY + 1).setValue(newQty);
      break;
    }
  }

  if (rowIndex === -1) {
    return { success: false, message: "Item ID not found" };
  }

  // Determine action string to save
  var actionTypeToSave = explicitActionType;
  if (!actionTypeToSave) {
     actionTypeToSave = quantityChange < 0 ? "USE" : "RESTOCK";
  }

  var logId = new Date().getTime().toString();
  var timestamp = new Date().toISOString();

  logSheet.appendRow([
    logId, 
    timestamp, 
    itemId, 
    currentName, 
    user, 
    quantityChange, 
    actionTypeToSave
  ]);

  return { success: true };
}
```

import React, { useEffect, useRef, useState } from 'react';
import { Html5Qrcode } from 'html5-qrcode';
import { X, Camera } from 'lucide-react';

interface QRScannerProps {
  onScanSuccess: (decodedText: string) => void;
  onClose: () => void;
}

const QRScanner: React.FC<QRScannerProps> = ({ onScanSuccess, onClose }) => {
  const [scanError, setScanError] = useState<string | null>(null);
  const scannerRef = useRef<Html5Qrcode | null>(null);

  useEffect(() => {
    // ID of the HTML element
    const elementId = "reader";

    // Create instance
    const html5QrCode = new Html5Qrcode(elementId);
    scannerRef.current = html5QrCode;

    const startScanner = async () => {
      try {
        // Configuration for the scanner
        const config = { 
          fps: 10, 
          qrbox: { width: 250, height: 250 },
          aspectRatio: 1.0
        };

        // Start scanning using the back camera (environment)
        await html5QrCode.start(
          { facingMode: "environment" }, 
          config,
          (decodedText) => {
            // Success callback
            // Stop scanning immediately to prevent duplicate reads
            html5QrCode.stop().then(() => {
              html5QrCode.clear();
              onScanSuccess(decodedText);
            }).catch(err => {
              console.error("Failed to stop scanner", err);
              onScanSuccess(decodedText);
            });
          },
          (errorMessage) => {
            // Error callback (scanned frame but no QR code found)
            // We ignore this to keep logs clean
          }
        );
      } catch (err) {
        console.error("Error starting scanner", err);
        setScanError("Kameraa ei voitu käynnistää. Varmista, että annoit luvan kameran käyttöön.");
      }
    };

    // Small delay to ensure DOM is ready
    setTimeout(startScanner, 100);

    // Cleanup function
    return () => {
      if (scannerRef.current) {
        if (scannerRef.current.isScanning) {
          scannerRef.current.stop().then(() => {
            scannerRef.current?.clear();
          }).catch(err => console.error("Error stopping scanner cleanup", err));
        } else {
           scannerRef.current.clear();
        }
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="fixed inset-0 z-50 bg-black flex flex-col items-center justify-center p-0">
      <div className="w-full h-full relative flex flex-col">

        {/* Header Overlay */}
        <div className="absolute top-0 left-0 right-0 z-10 p-4 flex justify-between items-center bg-gradient-to-b from-black/70 to-transparent text-white">
          <div className="flex items-center gap-2">
            <Camera size={20} />
            <span className="font-bold">Skannaa QR</span>
          </div>
          <button 
            onClick={onClose} 
            className="p-2 bg-white/20 rounded-full hover:bg-white/30 backdrop-blur-sm"
          >
            <X size={24} />
          </button>
        </div>

        {/* Scanner Viewport */}
        <div className="flex-1 bg-black relative flex items-center justify-center overflow-hidden">
          <div id="reader" className="w-full h-full object-cover"></div>

          {/* Visual guide overlay */}
          <div className="absolute inset-0 border-2 border-white/30 pointer-events-none flex items-center justify-center">
            <div className="w-64 h-64 border-2 border-red-500 rounded-lg shadow-[0_0_0_9999px_rgba(0,0,0,0.5)]"></div>
          </div>
        </div>

        {/* Error Message */}
        {scanError && (
          <div className="absolute bottom-20 left-4 right-4 bg-red-600 text-white p-4 rounded-lg text-center shadow-lg">
            {scanError}
          </div>
        )}

        {/* Footer Instructions */}
        <div className="absolute bottom-0 left-0 right-0 p-8 bg-gradient-to-t from-black/80 to-transparent text-center text-white pb-10">
           <p className="text-sm opacity-90">Osoita kamera tuotteen QR-koodiin.</p>
        </div>
      </div>
    </div>
  );
};

export default QRScanner;

import React, { useState, useEffect, useCallback } from 'react';
import { QrCode, ClipboardList, History, Search, RefreshCw, AlertCircle, Printer, ArrowDownLeft, ArrowUpRight, Plus } from 'lucide-react';
import { InventoryItem, UsageLog, AppView } from './types';
import { api } from './services/api';
import QRScanner from './components/QRScanner';
import UsageModal from './components/UsageModal';
import LabelPrinter from './components/LabelPrinter';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [logs, setLogs] = useState<UsageLog[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [statusMsg, setStatusMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);

  const loadData = useCallback(async () => {
    setLoading(true);
    setStatusMsg(null);
    try {
      // Load inventory first to ensure main view works
      const itemsData = await api.getInventory();
      setItems(itemsData);

      // Load logs separately so one failure doesn't block the other
      try {
        const logsData = await api.getLogs();
        setLogs(logsData);
      } catch (e) {
        console.warn("Could not load logs", e);
      }

    } catch (e) {
      console.error(e);
      setStatusMsg({ 
        type: 'error', 
        text: 'Yhteysvirhe. Tarkista että Google Script on julkaistu "Anyone" -oikeuksilla.' 
      });
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Handle QR Scan Result
  const handleScanSuccess = (decodedText: string) => {
    // Attempt to find item by QR code
    // Matches either the explicit qrCode field OR the row ID
    const found = items.find(i => i.qrCode === decodedText || i.id === decodedText);

    if (found) {
      setSelectedItem(found);
      setView(AppView.DASHBOARD); // Close scanner view, modal will open
    } else {
      alert(`Tuotetta koodilla "${decodedText}" ei löytynyt.`);
      setView(AppView.DASHBOARD);
    }
  };

  const handleTransaction = async (qty: number, user: string, actionType: 'USE' | 'RESTOCK' | 'RETURN') => {
    if (!selectedItem) return;
    setIsSubmitting(true);

    const success = await api.logUsage(selectedItem.id, qty, user, actionType);

    if (success) {
      setStatusMsg({ type: 'success', text: 'Kirjaus tallennettu onnistuneesti!' });
      setSelectedItem(null);
      await loadData(); // Refresh data
    } else {
      setStatusMsg({ type: 'error', text: 'Tallennus epäonnistui. Tarkista yhteys.' });
    }

    setIsSubmitting(false);
    setTimeout(() => setStatusMsg(null), 5000);
  };

  const filteredItems = items.filter(i => 
    i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    i.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const renderLogIcon = (action: string) => {
    switch(action) {
      case 'USE': return <ArrowUpRight size={16} className="text-red-500" />;
      case 'RETURN': return <ArrowDownLeft size={16} className="text-blue-500" />;
      case 'RESTOCK': return <Plus size={16} className="text-green-500" />;
      default: return <div />;
    }
  };

  const getActionLabel = (action: string) => {
    switch(action) {
      case 'USE': return 'Käyttö';
      case 'RETURN': return 'Palautus';
      case 'RESTOCK': return 'Täydennys';
      default: return action;
    }
  }

  return (
    <div className="min-h-screen pb-20 max-w-lg mx-auto bg-gray-50 shadow-2xl overflow-hidden relative border-x border-gray-200">
      {/* Header */}
      <header className="bg-white text-gray-800 p-6 shadow-sm sticky top-0 z-10 border-b border-gray-200">
        <div className="flex justify-between items-start mb-4">
           <div>
             {/* Logo Placeholder - User should save logo.png in public folder */}
             <img src="logo.png" alt="Turvallisuuskeskus" className="h-10 object-contain mb-3" onError={(e) => {
               (e.target as HTMLImageElement).style.display = 'none';
             }} />
             <h1 className="text-2xl font-bold tracking-tight text-gray-900">Harjoitusalue</h1>
             <p className="text-gray-500 text-xs">Varastonhallinta</p>
           </div>
           <div className="flex gap-2">
            <button 
                onClick={() => setView(AppView.PRINT_LABELS)} 
                className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
                title="Tulosta QR-tarrat"
              >
               <Printer size={20} />
             </button>
             <button onClick={loadData} className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
               <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
             </button>
           </div>
        </div>

        {/* Stats Summary - Updated colors to match logo (Cyan/Blue theme) */}
        <div className="flex gap-4">
          <div className="bg-cyan-50 border border-cyan-100 rounded-lg p-3 flex-1">
             <span className="block text-2xl font-bold text-gray-900">{items.length}</span>
             <span className="text-xs text-cyan-800 font-medium">Nimikettä</span>
          </div>
           <div className="bg-cyan-50 border border-cyan-100 rounded-lg p-3 flex-1">
             <span className="block text-2xl font-bold text-gray-900">{logs.length}</span>
             <span className="text-xs text-cyan-800 font-medium">Tapahtumaa</span>
          </div>
        </div>
      </header>

