}

import React, { useState, useEffect, useCallback } from 'react';
import { QrCode, ClipboardList, History, Search, RefreshCw, AlertCircle, Printer, ArrowDownLeft, ArrowUpRight, Plus, Wrench } from 'lucide-react';
import { InventoryItem, UsageLog, AppView } from './types';
import { api } from './services/api';
import QRScanner from './components/QRScanner';
