      case 'RETURN': return <ArrowDownLeft size={16} className="text-blue-500" />;
      case 'RESTOCK': return <Plus size={16} className="text-green-500" />;
      case 'CORRECTION': return <Wrench size={16} className="text-amber-500" />;
