import React, { useState } from 'react';
import { InventoryItem } from '../types';
import { Check, X, AlertTriangle, ArrowDownToLine, ArrowUpFromLine, PlusCircle, Wrench } from 'lucide-react';

interface UsageModalProps {
  item: InventoryItem;
  onConfirm: (quantity: number, user: string, actionType: 'USE' | 'RESTOCK' | 'RETURN' | 'CORRECTION') => void;
  onCancel: () => void;
  isSubmitting: boolean;
}

type ActionMode = 'USE' | 'RETURN' | 'RESTOCK' | 'CORRECTION';

const STORAGE_USER_KEY = 'rescue_inventory_last_user';

const UsageModal: React.FC<UsageModalProps> = ({ item, onConfirm, onCancel, isSubmitting }) => {
  const [amount, setAmount] = useState<string>('1');

  // Initialize user from LocalStorage if available
  const [user, setUser] = useState<string>(() => {
    return localStorage.getItem(STORAGE_USER_KEY) || '';
  });

  const [mode, setMode] = useState<ActionMode>('USE');

  const handleModeChange = (newMode: ActionMode) => {
    setMode(newMode);
    // If switching to correction, set amount to current quantity for easier editing
    // If switching to others, reset to 1
    if (newMode === 'CORRECTION') {
      setAmount(item.quantity.toString());
    } else {
      setAmount('1');
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const inputVal = parseInt(amount, 10);
    if (isNaN(inputVal)) return;

    // For standard modes, amount must be positive.
    // For Correction, it can be 0 (if stock is empty).
    if (mode !== 'CORRECTION' && inputVal <= 0) return;
    if (mode === 'CORRECTION' && inputVal < 0) return; // Stock can't be negative

    if (!user.trim()) return;

    // Save username to LocalStorage for next time
    localStorage.setItem(STORAGE_USER_KEY, user);

    let finalAmount = 0;

    if (mode === 'USE') {
      finalAmount = -inputVal;
    } else if (mode === 'RETURN' || mode === 'RESTOCK') {
      finalAmount = inputVal;
    } else if (mode === 'CORRECTION') {
      // Calculate difference: Target - Current
      // Example: Current 12, True Stock (Input) 10. Difference = -2.
      finalAmount = inputVal - item.quantity;
      if (finalAmount === 0) {
        // No change needed
        onCancel();
        return;
      }
    }

    onConfirm(finalAmount, user, mode);
  };

  const currentStock = item.quantity;
  const requested = parseInt(amount) || 0;

  const isStockLow = mode === 'USE' && (currentStock - requested < 0);

  // Calculate correction difference for display
  const correctionDiff = mode === 'CORRECTION' ? requested - currentStock : 0;

  const getThemeColor = () => {
    switch (mode) {
      case 'USE': return 'bg-red-600';
      case 'RETURN': return 'bg-blue-600';
      case 'RESTOCK': return 'bg-green-600';
      case 'CORRECTION': return 'bg-amber-500';
      default: return 'bg-gray-600';
    }
  };

  const getButtonColor = () => {
    switch (mode) {
      case 'USE': return 'bg-red-600 hover:bg-red-700 disabled:bg-red-300';
      case 'RETURN': return 'bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300';
      case 'RESTOCK': return 'bg-green-600 hover:bg-green-700 disabled:bg-green-300';
      case 'CORRECTION': return 'bg-amber-500 hover:bg-amber-600 disabled:bg-amber-300 text-black';
    }
  };

  const getTitle = () => {
    switch (mode) {
      case 'USE': return 'Kirjaa Otto';
      case 'RETURN': return 'Kirjaa Palautus';
      case 'RESTOCK': return 'Kirjaa Täydennys';
      case 'CORRECTION': return 'Korjaa Saldo';
    }
  };

  return (
    <div className="fixed inset-0 z-40 bg-black bg-opacity-75 flex items-center justify-center p-4">
      <form onSubmit={handleSubmit} className="w-full max-w-sm bg-white rounded-xl shadow-2xl overflow-hidden">
        {/* Header */}
        <div className={`p-4 text-white flex justify-between items-center transition-colors duration-300 ${getThemeColor()}`}>
          <h3 className={`text-lg font-bold ${mode === 'CORRECTION' ? 'text-black' : 'text-white'}`}>{getTitle()}</h3>
          <button type="button" onClick={onCancel} className="text-white hover:bg-white/20 rounded-full p-1">
            <X size={20} color={mode === 'CORRECTION' ? 'black' : 'white'} />
          </button>
        </div>

        <div className="p-6 space-y-4">

          {/* Item Info */}
          <div className="mb-4">
            <h4 className="text-xl font-bold text-gray-800">{item.name}</h4>
            <p className="text-sm text-gray-500 uppercase tracking-wide">{item.category}</p>
            <div className="mt-2 flex items-center gap-2">
              <span className="text-sm font-semibold text-gray-600">Nykyinen varasto:</span>
              <span className={`text-lg font-mono font-bold ${item.quantity < 5 ? 'text-red-500' : 'text-gray-800'}`}>
                {item.quantity} {item.unit}
              </span>
            </div>
          </div>

          {/* Mode Toggle */}
          <div className="grid grid-cols-4 bg-gray-100 p-1 rounded-lg gap-1">
            <button
              type="button"
              onClick={() => handleModeChange('USE')}
              className={`py-2 text-[10px] font-medium rounded-md transition-all flex flex-col items-center gap-1
                ${mode === 'USE' ? 'bg-white text-red-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200'}`}
            >
              <ArrowUpFromLine size={16} />
              Ota
            </button>
            <button
              type="button"
              onClick={() => handleModeChange('RETURN')}
              className={`py-2 text-[10px] font-medium rounded-md transition-all flex flex-col items-center gap-1
                ${mode === 'RETURN' ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200'}`}
            >
               <ArrowDownToLine size={16} />
              Palauta
            </button>
            <button
              type="button"
              onClick={() => handleModeChange('RESTOCK')}
              className={`py-2 text-[10px] font-medium rounded-md transition-all flex flex-col items-center gap-1
                ${mode === 'RESTOCK' ? 'bg-white text-green-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200'}`}
            >
               <PlusCircle size={16} />
              Lisää
            </button>
            <button
              type="button"
              onClick={() => handleModeChange('CORRECTION')}
              className={`py-2 text-[10px] font-medium rounded-md transition-all flex flex-col items-center gap-1
                ${mode === 'CORRECTION' ? 'bg-white text-amber-600 shadow-sm' : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200'}`}
            >
               <Wrench size={16} />
              Korjaa
            </button>
          </div>

          {/* Inputs */}
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              {mode === 'CORRECTION' ? 'Todellinen määrä hyllyssä' : `Määrä (${item.unit})`}
            </label>
            <input
              type="number"
              min={mode === 'CORRECTION' ? "0" : "1"}
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="w-full text-center text-3xl font-bold p-3 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none border-gray-300"
              required
            />

            {/* Warning / Info Messages */}
            {isStockLow && (
              <div className="mt-2 text-red-500 text-sm flex items-center gap-1 animate-pulse">
                <AlertTriangle size={16} />
                <span>Varoitus: Varasto menee miinukselle!</span>
              </div>
            )}

            {mode === 'CORRECTION' && (
              <div className="mt-2 p-2 bg-amber-50 border border-amber-100 rounded text-sm text-amber-900">
                <span className="font-semibold">Muutos: </span>
                <span className="font-mono">{correctionDiff > 0 ? '+' : ''}{correctionDiff} {item.unit}</span>
                <p className="text-xs text-amber-700 mt-1">Ohjelma laskee automaattisesti erotuksen.</p>
              </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Käyttäjän nimi</label>
            <input
              type="text"
              value={user}
              onChange={(e) => setUser(e.target.value)}
              placeholder="Esim. Matti M."
              className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
              required
            />
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-4 bg-gray-50 border-t flex gap-3">
          <button
            type="button"
            onClick={onCancel}
            className="flex-1 py-3 px-4 bg-white border border-gray-300 text-gray-700 font-medium rounded-lg hover:bg-gray-50 transition-colors"
          >
            Peruuta
          </button>
          <button
            type="submit"
            disabled={isSubmitting || !user.trim()}
            className={`flex-1 py-3 px-4 text-white font-medium rounded-lg flex justify-center items-center gap-2 transition-colors ${getButtonColor()}`}
          >
            {isSubmitting ? 'Tallennetaan...' : (
              <>
                <Check size={20} />
                {mode === 'CORRECTION' ? 'Korjaa' : 'Tallenna'}
              </>
            )}
          </button>
        </div>
      </form>
    </div>
  );
};

export default UsageModal;

import { InventoryItem, UsageLog, ApiResponse } from '../types';
import { INITIAL_ITEMS, INITIAL_LOGS, GOOGLE_SCRIPT_URL } from '../constants';

// Local storage keys for mock persistence
const STORAGE_ITEMS_KEY = 'rescue_inventory_items';
const STORAGE_LOGS_KEY = 'rescue_inventory_logs';

const isDemo = !GOOGLE_SCRIPT_URL;

// Helper to simulate delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export const api = {
  /**
   * Fetch all inventory items
   */
  getInventory: async (): Promise<InventoryItem[]> => {
    if (isDemo) {
      await delay(600);
      const stored = localStorage.getItem(STORAGE_ITEMS_KEY);
      if (stored) return JSON.parse(stored);
      localStorage.setItem(STORAGE_ITEMS_KEY, JSON.stringify(INITIAL_ITEMS));
      return INITIAL_ITEMS;
    } else {
      try {
        // Add timestamp to prevent caching
        const params = new URLSearchParams({ 
          action: 'getInventory', 
          _t: Date.now().toString() 
        });

        const response = await fetch(`${GOOGLE_SCRIPT_URL}?${params.toString()}`, {
          method: 'GET',
          redirect: 'follow'
        });

        if (!response.ok) {
          throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data: ApiResponse<InventoryItem[]> = await response.json();

        if (!data.success) {
           console.error("API reported error:", data.message);
           return [];
        }

        return data.data || [];
      } catch (error) {
        console.error("API Error getInventory. Check if script is deployed as 'Anyone'.", error);
        throw error; // Re-throw so App can show error state
      }
    }
  },

  /**
   * Log usage and update stock
   * @param itemId 
   * @param quantity Negative for removing, Positive for adding
   * @param user 
   * @param actionType Optional explicit action type (USE, RESTOCK, RETURN, CORRECTION)
   */
  logUsage: async (itemId: string, quantity: number, user: string, actionType: 'USE' | 'RESTOCK' | 'RETURN' | 'CORRECTION'): Promise<boolean> => {

    if (isDemo) {
      await delay(800);

      // Update Items
      const storedItemsStr = localStorage.getItem(STORAGE_ITEMS_KEY);
      const items: InventoryItem[] = storedItemsStr ? JSON.parse(storedItemsStr) : INITIAL_ITEMS;
      const updatedItems = items.map(item => {
        if (item.id === itemId) {
          return { ...item, quantity: item.quantity + quantity }; 
        }
        return item;
      });
      localStorage.setItem(STORAGE_ITEMS_KEY, JSON.stringify(updatedItems));

      // Add Log
      const storedLogsStr = localStorage.getItem(STORAGE_LOGS_KEY);
      const logs: UsageLog[] = storedLogsStr ? JSON.parse(storedLogsStr) : INITIAL_LOGS;

      const targetItem = items.find(i => i.id === itemId);

      const newLog: UsageLog = {
        id: Date.now().toString(),
        timestamp: new Date().toISOString(),
        itemId,
        itemName: targetItem?.name || 'Unknown',
        user,
        amountChanged: quantity,
        action: actionType
      };

      localStorage.setItem(STORAGE_LOGS_KEY, JSON.stringify([newLog, ...logs]));
      return true;
    } else {
      // Real API Call
      try {
        const payload = {
          action: 'logUsage',
          itemId,
          quantity, 
          user,
          actionType // Send explicit type
        };

        // Critical: use text/plain to avoid CORS preflight (OPTIONS) which GAS doesn't handle
        // backend-script.gs must use JSON.parse(e.postData.contents)
        const response = await fetch(GOOGLE_SCRIPT_URL, {
          method: 'POST',
          redirect: 'follow',
          headers: {
            'Content-Type': 'text/plain;charset=utf-8',
          },
          body: JSON.stringify(payload)
        });

        if (!response.ok) {
           throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data = await response.json();
        if (!data.success) {
          console.error("API returned failure:", data.message);
          return false;
        }
        return true;
      } catch (error) {
        console.error("API Error logUsage", error);
        return false;
      }
    }
  },

  /**
   * Get logs
   */
  getLogs: async (): Promise<UsageLog[]> => {
    if (isDemo) {
      await delay(500);
      const stored = localStorage.getItem(STORAGE_LOGS_KEY);
      if (stored) return JSON.parse(stored);
      return INITIAL_LOGS;
    } else {
       try {
        const params = new URLSearchParams({ 
          action: 'getLogs',
          _t: Date.now().toString() 
        });

        const response = await fetch(`${GOOGLE_SCRIPT_URL}?${params.toString()}`, {
           method: 'GET',
           redirect: 'follow'
        });

        if (!response.ok) {
           throw new Error(`HTTP error! status: ${response.status}`);
        }

        const data: ApiResponse<UsageLog[]> = await response.json();
        return data.data || [];
      } catch (error) {
        console.error("API Error getLogs", error);
        return [];
      }
    }
  }
};

export interface InventoryItem {
  id: string;
  name: string;
  category: string;
  quantity: number;
  unit: string;
  qrCode: string;
}

export interface UsageLog {
  id: string;
  timestamp: string;
  itemId: string;
  itemName: string;
  user: string;
  amountChanged: number;
  action: 'USE' | 'RESTOCK' | 'RETURN' | 'CORRECTION';
}

export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  message?: string;
}

// Enum for App View State
export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SCANNER = 'SCANNER',
  ITEM_DETAILS = 'ITEM_DETAILS',
  LOGS = 'LOGS',
  PRINT_LABELS = 'PRINT_LABELS',
  SIMPLE_SCANNER = 'SIMPLE_SCANNER'
}

import React, { useState, useEffect, useCallback } from 'react';
import { QrCode, ClipboardList, History, Search, RefreshCw, AlertCircle, Printer, ArrowDownLeft, ArrowUpRight, Plus, Wrench, Maximize, Minimize, CheckCircle } from 'lucide-react';
import { InventoryItem, UsageLog, AppView } from './types';
import { api } from './services/api';
import QRScanner from './components/QRScanner';
import UsageModal from './components/UsageModal';
import LabelPrinter from './components/LabelPrinter';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.DASHBOARD);
  const [items, setItems] = useState<InventoryItem[]>([]);
  const [logs, setLogs] = useState<UsageLog[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [selectedItem, setSelectedItem] = useState<InventoryItem | null>(null);
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [statusMsg, setStatusMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);

  // State for Kiosk Mode Success Overlay
  const [showSyncSuccess, setShowSyncSuccess] = useState<boolean>(false);

  const loadData = useCallback(async () => {
    setLoading(true);
    setStatusMsg(null);
    try {
      // Load inventory first to ensure main view works
      const itemsData = await api.getInventory();
      setItems(itemsData);

      // Load logs separately so one failure doesn't block the other
      try {
        const logsData = await api.getLogs();
        setLogs(logsData);
      } catch (e) {
        console.warn("Could not load logs", e);
      }

    } catch (e) {
      console.error(e);
      setStatusMsg({ 
        type: 'error', 
        text: 'Yhteysvirhe. Tarkista että Google Script on julkaistu "Anyone" -oikeuksilla.' 
      });
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadData();
  }, [loadData]);

  // Handle QR Scan Result
  const handleScanSuccess = (decodedText: string) => {
    // Attempt to find item by QR code
    // Matches either the explicit qrCode field OR the row ID
    const found = items.find(i => i.qrCode === decodedText || i.id === decodedText);

    if (found) {
      setSelectedItem(found);
      // If NOT in simple/kiosk mode, switch back to dashboard to show modal over it
      // If in SIMPLE_SCANNER mode, we stay in that view, but the conditional rendering
      // will hide the scanner and show the modal.
      if (view !== AppView.SIMPLE_SCANNER) {
        setView(AppView.DASHBOARD);
      }
    } else {
      alert(`Tuotetta koodilla "${decodedText}" ei löytynyt.`);
      if (view !== AppView.SIMPLE_SCANNER) {
        setView(AppView.DASHBOARD);
      }
    }
  };

  const handleTransaction = async (qty: number, user: string, actionType: 'USE' | 'RESTOCK' | 'RETURN' | 'CORRECTION') => {
    if (!selectedItem) return;
    setIsSubmitting(true);

    const success = await api.logUsage(selectedItem.id, qty, user, actionType);

    if (success) {
      await loadData(); // Refresh data immediately

      if (view === AppView.SIMPLE_SCANNER) {
        // KIOSK MODE FLOW
        setSelectedItem(null); // Close modal
        setShowSyncSuccess(true); // Show big success screen

        // Hide success screen after delay and let Scanner remount
        setTimeout(() => {
          setShowSyncSuccess(false);
        }, 2000);
      } else {
        // STANDARD FLOW
        setStatusMsg({ type: 'success', text: 'Kirjaus tallennettu onnistuneesti!' });
        setSelectedItem(null);
        setTimeout(() => setStatusMsg(null), 5000);
      }
    } else {
      setStatusMsg({ type: 'error', text: 'Tallennus epäonnistui. Tarkista yhteys.' });
    }

    setIsSubmitting(false);
  };

  const filteredItems = items.filter(i => 
    i.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    i.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const renderLogIcon = (action: string) => {
    switch(action) {
      case 'USE': return <ArrowUpRight size={16} className="text-red-500" />;
      case 'RETURN': return <ArrowDownLeft size={16} className="text-blue-500" />;
      case 'RESTOCK': return <Plus size={16} className="text-green-500" />;
      case 'CORRECTION': return <Wrench size={16} className="text-amber-500" />;
      default: return <div />;
    }
  };

  const getActionLabel = (action: string) => {
    switch(action) {
      case 'USE': return 'Käyttö';
      case 'RETURN': return 'Palautus';
      case 'RESTOCK': return 'Täydennys';
      case 'CORRECTION': return 'Korjaus';
      default: return action;
    }
  }

  // --- KIOSK MODE VIEW ---
  if (view === AppView.SIMPLE_SCANNER) {
    return (
      <div className="fixed inset-0 bg-black z-50 flex flex-col">
        {/* Success Overlay */}
        {showSyncSuccess && (
          <div className="absolute inset-0 z-[60] bg-green-600 flex flex-col items-center justify-center text-white animate-in fade-in duration-300">
            <CheckCircle size={80} className="mb-4 animate-bounce" />
            <h2 className="text-3xl font-bold text-center">Synkronointi onnistunut</h2>
            <p className="mt-2 opacity-90">Valmis seuraavaan...</p>
          </div>
        )}

        {/* Modal handles its own overlay. If item is selected, we hide scanner to save resources/conflicts */}
        {!selectedItem && !showSyncSuccess && (
          <QRScanner 
            onScanSuccess={handleScanSuccess} 
            onClose={() => setView(AppView.DASHBOARD)} 
          />
        )}

        {/* Custom Header for Kiosk Mode (Overlaying Scanner if needed, or if Scanner has its own header) */}
        {!selectedItem && !showSyncSuccess && (
           <div className="absolute top-4 right-4 z-[60]">
             <button 
               onClick={() => setView(AppView.DASHBOARD)}
               className="bg-black/50 text-white p-3 rounded-full backdrop-blur-md border border-white/20 hover:bg-black/70"
               title="Poistu Kioski-tilasta"
             >
               <Minimize size={24} />
             </button>
           </div>
        )}

        {selectedItem && (
          <div className="relative z-[55]">
            <UsageModal 
              item={selectedItem}
              onConfirm={handleTransaction}
              onCancel={() => setSelectedItem(null)}
              isSubmitting={isSubmitting}
            />
          </div>
        )}
      </div>
    );
  }

  // --- STANDARD DASHBOARD VIEW ---
  return (
    <div className="min-h-screen pb-20 max-w-lg mx-auto bg-gray-50 shadow-2xl overflow-hidden relative border-x border-gray-200">
      {/* Header */}
      <header className="bg-white text-gray-800 p-6 shadow-sm sticky top-0 z-10 border-b border-gray-200">
        <div className="flex justify-between items-start mb-4">
           <div>
             {/* Logo image */}
             <img 
               src="./logo.png" 
               alt="Turvallisuuskeskus" 
               className="h-12 object-contain mb-3" 
             />
             <h1 className="text-2xl font-bold tracking-tight text-gray-900">Harjoitusalue</h1>
             <p className="text-gray-500 text-xs">Varastonhallinta</p>
           </div>
           <div className="flex gap-2">
            <button 
                onClick={() => setView(AppView.SIMPLE_SCANNER)} 
                className="p-2 text-cyan-700 bg-cyan-50 hover:bg-cyan-100 border border-cyan-200 rounded-full transition-colors"
                title="Kioski-tila (Vain skannaus)"
              >
               <Maximize size={20} />
             </button>
            <button 
                onClick={() => setView(AppView.PRINT_LABELS)} 
                className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
                title="Tulosta QR-tarrat"
              >
               <Printer size={20} />
             </button>
             <button onClick={loadData} className="p-2 text-gray-600 hover:bg-gray-100 rounded-full transition-colors">
               <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
             </button>
           </div>
        </div>

        {/* Stats Summary */}
        <div className="flex gap-4">
          <div className="bg-cyan-50 border border-cyan-100 rounded-lg p-3 flex-1">
             <span className="block text-2xl font-bold text-gray-900">{items.length}</span>
             <span className="text-xs text-cyan-800 font-medium">Nimikettä</span>
          </div>
           <div className="bg-cyan-50 border border-cyan-100 rounded-lg p-3 flex-1">
             <span className="block text-2xl font-bold text-gray-900">{logs.length}</span>
             <span className="text-xs text-cyan-800 font-medium">Tapahtumaa</span>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="p-4">

        {/* Status Message Toast */}
        {statusMsg && (
          <div className={`mb-4 p-4 rounded-lg flex items-center gap-3 text-sm font-medium animate-bounce-in
            ${statusMsg.type === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
            <AlertCircle size={20} className="flex-shrink-0" />
            <span>{statusMsg.text}</span>
          </div>
        )}

        {view === AppView.DASHBOARD && (
          <div className="space-y-4">

            {/* Quick Action: Scan */}
            <button
              onClick={() => setView(AppView.SCANNER)}
              className="w-full bg-gray-900 text-white p-6 rounded-xl shadow-lg flex items-center justify-center gap-4 hover:bg-gray-800 transition-transform active:scale-95"
            >
              <QrCode size={32} />
              <div className="text-left">
                <span className="block text-lg font-bold">Skannaa tuote</span>
                <span className="text-gray-400 text-sm">Käytä kameraa kirjaukseen</span>
              </div>
            </button>

            {/* Inventory List Header & Search */}
            <div className="mt-8">
              <div className="flex justify-between items-center mb-4">
                 <h2 className="text-lg font-bold text-gray-800">Varastotilanne</h2>
              </div>

              <div className="relative mb-4">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text" 
                  placeholder="Etsi tuotetta..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-3 bg-white border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-cyan-500"
                />
              </div>

              {/* Items List */}
              <div className="space-y-3">
                {loading && items.length === 0 ? (
                  <div className="text-center py-10 text-gray-400">Ladataan...</div>
                ) : filteredItems.length === 0 ? (
                  <div className="text-center py-10 text-gray-400">
                    {statusMsg?.type === 'error' ? 'Ei yhteyttä tietokantaan.' : 'Ei tuotteita tai haku ei tuottanut tuloksia.'}
                  </div>
                ) : (
                  filteredItems.map(item => (
                    <div 
                      key={item.id} 
                      onClick={() => setSelectedItem(item)}
                      className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex justify-between items-center active:bg-gray-50 cursor-pointer"
                    >
                      <div>
                        <h3 className="font-semibold text-gray-800">{item.name}</h3>
                        <span className="inline-block px-2 py-0.5 bg-gray-100 text-gray-500 text-xs rounded-md mt-1">
                          {item.category}
                        </span>
                      </div>
                      <div className="text-right">
                        <div className={`text-xl font-mono font-bold ${item.quantity < 5 ? 'text-red-500' : 'text-gray-800'}`}>
                          {item.quantity}
                        </div>
                        <span className="text-xs text-gray-400">{item.unit}</span>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}

        {view === AppView.LOGS && (
          <div className="space-y-4">
            <h2 className="text-lg font-bold text-gray-800 mb-4">Käyttöhistoria</h2>
            <div className="bg-white rounded-xl shadow-sm border border-gray-100 divide-y">
              {logs.map((log) => (
                <div key={log.id} className="p-4 flex justify-between items-start">
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      {renderLogIcon(log.action)}
                      <span className="font-medium text-gray-800">{log.itemName}</span>
                    </div>
                    <div className="text-sm text-gray-500 flex flex-col sm:flex-row sm:gap-2">
                       <span className="text-xs font-semibold bg-gray-100 px-1.5 py-0.5 rounded text-gray-600 w-fit">{getActionLabel(log.action)}</span>
                       <span className="flex items-center gap-1">{log.user}</span>
                       <span className="hidden sm:inline text-gray-300">•</span>
                       <span className="text-xs text-gray-400 mt-0.5 sm:mt-0">{new Date(log.timestamp).toLocaleString('fi-FI')}</span>
                    </div>
                  </div>
                  <div className={`font-mono font-bold ${log.amountChanged < 0 ? 'text-red-500' : 'text-green-600'} ${log.action === 'CORRECTION' ? 'text-amber-600' : ''}`}>
                    {log.amountChanged > 0 ? '+' : ''}{log.amountChanged}
                  </div>
                </div>
              ))}
              {logs.length === 0 && <div className="p-6 text-center text-gray-400">Ei historiaa.</div>}
            </div>
          </div>
        )}

      </main>

      {/* Navigation Bar */}
      <nav className="fixed bottom-0 w-full max-w-lg bg-white border-t border-gray-200 flex justify-around p-2 pb-4 z-20">
        <button 
          onClick={() => setView(AppView.DASHBOARD)}
          className={`p-2 flex flex-col items-center gap-1 min-w-[64px] ${view === AppView.DASHBOARD ? 'text-cyan-600' : 'text-gray-400'}`}
        >
          <ClipboardList size={24} />
          <span className="text-[10px] font-medium">Varasto</span>
        </button>

        <div className="relative -top-6">
          <button 
            onClick={() => setView(AppView.SCANNER)}
            className="bg-gray-900 text-white p-4 rounded-full shadow-lg hover:bg-gray-800 hover:scale-105 transition-all"
          >
            <QrCode size={28} />
          </button>
        </div>

        <button 
          onClick={() => setView(AppView.LOGS)}
          className={`p-2 flex flex-col items-center gap-1 min-w-[64px] ${view === AppView.LOGS ? 'text-cyan-600' : 'text-gray-400'}`}
        >
          <History size={24} />
          <span className="text-[10px] font-medium">Logi</span>
        </button>
      </nav>

      {/* Overlays */}
      {view === AppView.SCANNER && (
        <QRScanner 
          onScanSuccess={handleScanSuccess} 
          onClose={() => setView(AppView.DASHBOARD)} 
        />
      )}

      {view === AppView.PRINT_LABELS && (
        <LabelPrinter 
          items={items} 
          onClose={() => setView(AppView.DASHBOARD)} 
        />
      )}

      {selectedItem && (
        <UsageModal 
          item={selectedItem}
          onConfirm={handleTransaction}
          onCancel={() => setSelectedItem(null)}
          isSubmitting={isSubmitting}
        />
      )}
    </div>
  );
};

export default App;
